1	const PROCESSING_FEE = 5;
2	const COMPONENT_BASE_PREMIUM = 25;
3	const COMPONENT_BLOCK_SIZE = 3;
4	const COMPONENT_BLOCK_PREMIUM = 60;
5	
6	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	};
12	
13	type Item = { type: string };
14	type Step = { op: "quote"; items: Item[] };
15	type Scenario = { customer: unknown; steps: Step[] };
16	
17	const isMainItem = ({ type }: Item): boolean => type in BASE_PREMIUM_BY_TYPE;
18	
19	const basePremiumForMainItem = ({ type }: Item): number =>
20	  BASE_PREMIUM_BY_TYPE[type] ?? 0;
21	
22	const priceComponentGroup = (count: number): number =>
23	  count === COMPONENT_BLOCK_SIZE
24	    ? COMPONENT_BLOCK_PREMIUM
25	    : count * COMPONENT_BASE_PREMIUM;
26	
27	const countByType = (items: Item[]): Map<string, number> =>
28	  items.reduce(
29	    (counts, { type }) => counts.set(type, (counts.get(type) ?? 0) + 1),
30	    new Map<string, number>(),
31	  );
32	
33	const sumComponentPremiums = (components: Item[]): number =>
34	  [...countByType(components).values()]
35	    .reduce((sum, count) => sum + priceComponentGroup(count), 0);
36	
37	const sumBasePremiums = (items: Item[]): number => {
38	  const mains = items.filter(isMainItem);
39	  const components = items.filter((i) => !isMainItem(i));
40	  const mainsSum = mains.reduce((sum, item) => sum + basePremiumForMainItem(item), 0);
41	  return mainsSum + sumComponentPremiums(components);
42	};
43	
44	const quotePremiumFor = (step: Step): { premium: number } => ({
45	  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
46	});
47	
48	export const runScenario = (scenario: Scenario): { results: unknown[] } => ({
49	  results: scenario.steps.map(quotePremiumFor),
50	});
