  items.reduce<{ mains: Item[]; components: Item[] }>(
    (acc, item) => {
      (isMainItem(item) ? acc.mains : acc.components).push(item);
      return acc;
    },
    { mains: [], components: [] },
  );

const sumBasePremiums = (items: Item[]): number => {
  const { mains, components } = partitionItems(items);
  return (
    mains.reduce((sum, item) => sum + basePremiumForMainItem(item), 0) +
    sumComponentPremiums(components)
  );
};

